## 3. TypeScript — sum(numbers)
Wynik: 100

```typescript
/**
 * Zwraca sumę wszystkich liczb w podanej tablicy.
 * Jeśli tablica jest pusta, zwraca 0.
 */
function sum(numbers: number[]): number {
  return numbers.reduce((accumulator, currentValue) => accumulator + currentValue, 0);
}
