// Factorial oblicza silnię liczby n (n!).
// Dla n >= 0. Silnia z 0 wynosi 1.
func Factorial(n int) int {
    if n < 0 {
        // W wersji produkcyjnej lepiej zwrócić błąd, ale tutaj zwracamy -1
