  }
  return reversed;
}
```

## 3. Za pomocą operatora spread i reduce

```javascript
function reverseString(str) {
  return [...str].reduce((reversed, char) => char + reversed, '');
}
```

## 4. Rekurencyjnie

```javascript
function reverseString(str) {
  if (str === '') return '';
  return reverseString(str.substr(1)) + str[0];
}
```

