bool isAnagram(String a, String b) {
  // Usuwamy spacje i zamieniamy na małe litery
  String normalize(String s) => s.replaceAll(' ', '').toLowerCase();

  final normalizedA = normalize(a);
  final normalizedB = normalize(b);

  // Jeśli ciągi różnej długości po normalizacji – nie są anagramami
  if (normalizedA.length != normalizedB.length) return false;

  // Sortujemy znaki i porównujemy
  final sortedA = (normalizedA.split('')..sort()).join();
  final sortedB = (normalizedB.split('')..sort()).join();

  return sortedA == sortedB;
}
```

