/**
 * Returns a new vector containing the squares of the elements from the input vector.
 *
 * @param numbers  input vector of integers (read-only)
 * @return         vector of squares (same size as input)
 */
std::vector<int> squares(const std::vector<int>& numbers) {
    std::vector<int> result;
    result.reserve(numbers.size());         // avoid reallocations
    for (int x : numbers) {
